class Solution:
    def isValidSudoku(self, board: List[List[str]]) -> bool:
        # 构建哈希表
        # 遍历每个数字，并按照规则进行分类
        dic = collections.defaultdict(list)
        for i in range(9):
            for j in range(9):
                if board[i][j] != '.':
                    digit = int(board[i][j])
                    # 将当前数字添加到所在行和列的集合中
                    dic[i].append(digit)
                    dic[~j].append(digit)
                    # 将当前数字添加到所在的小九宫格的集合中
                    dic[(i // 3, j // 3)].append(digit)
                    # 如果出现重复，则说明数独无效
                    if len(dic[i]) != len(set(dic[i])) or len(dic[~j]) != len(set(dic[~j])) or len(dic[(i // 3, j // 3)]) != len(set(dic[(i // 3, j // 3)])):
                        return False
        return True
